const item = $input.first().json.data.items[0];
const cols = {};
item.column_values.forEach(c => { cols[c.id] = c.text; });
const asset = item.assets?.[0];

return [{
  json: {
    monday_item_id:      item.id,
    titulo:              item.name,
    tipo:                (cols.color_mm4p82jm || '').toLowerCase().trim(),
    modo_envio:          (cols.color_mm4p5bh9 || '').toUpperCase().trim(),
    empresa:             (cols.text_mm4pw5c4 || '').toUpperCase().trim(),
    segmento:            cols.text_mm4peyyh || '',
