        "jsCode": "const item = $input.first().json.data.items[0];
const cols = {};
item.column_values.forEach(c => { cols[c.id] = c.text; });
const asset = item.assets?.[0];

return [{
  json: {
    monday_item_id:      item.id,
    titulo:              item.name,
